#!/bin/bash

#set -e

root_path=$(cd $(dirname $0);pwd)
#echo "root_path: "${root_path}
cd ${root_path}
script_name=$0

usage(){
	echo "$script_name ap_type"
	echo "ap_type    : he | vht | ht | non-ht | non-ht-2g4 | ht-2g4 | he-2g4"
	echo ""
}

file_path=/tmp
file_path=./tmp
if [ ! -d $file_path ];then
mkdir -p $file_path
fi

echo "arg:$#"
if [ $# -eq 1 ]; then
	ap_type=$1
	echo "ap_type: " $ap_type
	echo -n "b0003a01aa00ccddeeff665544332211aa00ccddeeff1000000001000000" > $file_path/auth
	if [ "$ap_type" = "he" ];then
		echo -n "" > $file_path/assoc
	elif [ "$ap_type" = "vht" ];then
		echo -n "" > $file_path/assoc
	elif [ "$ap_type" = "ht" ];then
		echo -n "" > $file_path/assoc
	elif [ "$ap_type" = "non-ht" ];then
		echo -n "00003a01aa00ccddeeff665544332211aa00ccddeeff20002104050000046f70656e0108060c1809122430367f0a04000a02014000400001dd070050f202000101" > $file_path/assoc
	elif [ "$ap_type" = "non-ht-2g4" ];then
		echo -n "00003a01aa00ccddeeff665544332211aa00ccddeeff20002104050000046f70656e0108060c1809122430367f0a04000a02014000400001dd070050f202000101" > $file_path/assoc
	elif [ "$ap_type" = "ht-2g4" ];then
		echo -n "" > $file_path/assoc
	elif [ "$ap_type" = "he-2g4" ];then
		echo -n "" > $file_path/assoc
	fi
else
	usage;
fi


conf_path=/lib/firmware/clsm_wifi_settings.ini
if [ ! -f $conf_path ]; then
conf_path=./ap_clsm_wifi_settings.ini
if [ ! -f $conf_path ];then
touch $conf_path
echo -n "MAC_ADDR=80:11:cc:19:11:80" > $conf_path
fi
fi

if [ -f $conf_path ]; then
echo "set wlan0 | wlan1 mac"
sed -i '/MAC_ADDR1=/d'  $conf_path
sed -i "/MAC_ADDR=/c\MAC_ADDR=00:11:cc:19:11:00"  $conf_path
sed -i "/MAC_ADDR=/a\MAC_ADDR1=20:11:cc:19:11:20"  $conf_path
fi




